const body = $input.first().json.body;
const podpisId = body.podpisId || '';
const chatId   = String(body.chatId || '');
const message  = String(body.message || '');
return [{ json: { podpisId, chatId, message } }];

// v4.11: žiadny polling — chatId + message sú priamo v payloade
const { podpisId, chatId, message } = $input.first().json;
const cbBase = 'sign_' + podpisId + '_';
const tgBody = JSON.stringify({
  chat_id: chatId,
  text: message,
  parse_mode: 'HTML',
  reply_markup: { inline_keyboard: [[
    { text: '\u2705 Potvrdzujem',     callback_data: cbBase + 'confirm' },
    { text: '\u274c Nes\u00fahlasim', callback_data: cbBase + 'reject' }
  ]] }
});
return [{ json: { podpisId, chatId, tgBody } }];

const resp  = $input.first().json;
if (!resp.ok) {
  throw new Error('TG sendMessage failed: ' + (resp.description || JSON.stringify(resp)));
}
const msgId = (resp.result && resp.result.message_id) ? resp.result.message_id : 0;
const prev  = $('Build TG Body').first().json;
return [{ json: { podpisId: prev.podpisId, chatId: prev.chatId, messageId: msgId } }];

